INSERT INTO `department` VALUES (1,'Accounts','Manages client accounts, billing, and account-level customer relationships'),(2,'Customer Service','Handles customer inquiries, complaints, and after-sales support'),(3,'Executive','Senior leadership responsible for overall company strategy and operations'),(4,'Finance','Oversees financial planning, accounting, payroll processing, and reporting'),(5,'Human Resources','Manages recruitment, employee relations, benefits, and compliance'),(6,'IT','Maintains IT infrastructure, systems operations, and technical support'),(7,'Marketing','Drives brand strategy, promotions, and sales and marketing initiatives'),(8,'Supply Chain','Manages procurement, logistics, inventory, and supplier relationships');
/*!40000 ALTER TABLE `department` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `employee`
--

DROP TABLE IF EXISTS `employee`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `employee` (
  `employee_id` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `first_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `last_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `birthday` date NOT NULL,
  `address` text COLLATE utf8mb4_unicode_ci,
  `phone_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sss_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `philhealth_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tin_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pagibig_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('REGULAR','PROBATIONARY') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'REGULAR',
  `supervisor_id` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`employee_id`),
  UNIQUE KEY `sss_number` (`sss_number`),
  UNIQUE KEY `philhealth_number` (`philhealth_number`),
  UNIQUE KEY `tin_number` (`tin_number`),
  UNIQUE KEY `pagibig_number` (`pagibig_number`),
  KEY `idx_employee_names` (`last_name`,`first_name`),
  KEY `idx_employee_supervisor` (`supervisor_id`),
  CONSTRAINT `fk_employee_supervisor` FOREIGN KEY (`supervisor_id`) REFERENCES `employee` (`employee_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

